export const RetrievalMode = {
  Naive: 'naive',
  Graph: 'graph',
  AgenticDeepRead: 'agentic_deepread',
} as const;

export type RetrievalModeType =
  (typeof RetrievalMode)[keyof typeof RetrievalMode];

export type AgenticDeepReadConfig = {
  override_dataset_defaults: boolean;
  candidate_doc_topn: number;
  agent_max_rounds: number;
  retrieve_strategy: 'auto' | 'bm25' | 'hybrid';
  retrieve_topk: number;
  evidence_cap: number;
  neighbor_window_up: number;
  neighbor_window_down: number;
};

export const defaultAgenticDeepReadConfig: AgenticDeepReadConfig = {
  override_dataset_defaults: false,
  candidate_doc_topn: 4,
  agent_max_rounds: 6,
  retrieve_strategy: 'auto',
  retrieve_topk: 3,
  evidence_cap: 12,
  neighbor_window_up: 1,
  neighbor_window_down: 1,
};

export type AgenticDeepReadCorpusStatus =
  | 'pending'
  | 'ready'
  | 'fallback'
  | 'failed';

export const defaultAgenticDeepReadPrebuild = false;

const retrievalModeValues = new Set<string>(Object.values(RetrievalMode));
const retrieveStrategyValues = new Set<string>(['auto', 'bm25', 'hybrid']);

export function getRetrievalMode(config?: {
  retrieval_mode?: string;
  use_kg?: boolean;
}) {
  if (
    config?.retrieval_mode &&
    retrievalModeValues.has(config.retrieval_mode)
  ) {
    return config.retrieval_mode as RetrievalModeType;
  }
  return config?.use_kg ? RetrievalMode.Graph : RetrievalMode.Naive;
}

export function normalizeAgenticDeepReadConfig(
  config?: Partial<AgenticDeepReadConfig>,
): AgenticDeepReadConfig {
  const nextConfig = {
    ...defaultAgenticDeepReadConfig,
    ...(config ?? {}),
  };

  nextConfig.retrieve_strategy = retrieveStrategyValues.has(
    nextConfig.retrieve_strategy,
  )
    ? nextConfig.retrieve_strategy
    : defaultAgenticDeepReadConfig.retrieve_strategy;

  return nextConfig;
}

export function normalizePromptConfigWithAgenticDeepRead<
  T extends {
    retrieval_mode?: string;
    use_kg?: boolean;
    agentic_deepread?: Partial<AgenticDeepReadConfig>;
  },
>(
  promptConfig?: T,
): T & {
  retrieval_mode: RetrievalModeType;
  agentic_deepread: AgenticDeepReadConfig;
} {
  const nextPromptConfig = { ...(promptConfig ?? {}) } as T;
  return {
    ...nextPromptConfig,
    retrieval_mode: getRetrievalMode(nextPromptConfig),
    agentic_deepread: normalizeAgenticDeepReadConfig(
      nextPromptConfig.agentic_deepread,
    ),
  };
}

export function normalizeParserConfigWithAgenticDeepRead<
  T extends {
    agentic_deepread_prebuild?: boolean;
    agentic_deepread_defaults?: Partial<AgenticDeepReadConfig>;
  },
>(
  parserConfig?: T,
): T & {
  agentic_deepread_prebuild: boolean;
  agentic_deepread_defaults: AgenticDeepReadConfig;
} {
  const nextParserConfig = { ...(parserConfig ?? {}) } as T;
  return {
    ...nextParserConfig,
    agentic_deepread_prebuild:
      nextParserConfig.agentic_deepread_prebuild ??
      defaultAgenticDeepReadPrebuild,
    agentic_deepread_defaults: normalizeAgenticDeepReadConfig(
      nextParserConfig.agentic_deepread_defaults,
    ),
  };
}

export function getAgenticDeepReadStatusLabel(
  status?: AgenticDeepReadCorpusStatus,
) {
  switch (status) {
    case 'pending':
      return 'Pending';
    case 'ready':
      return 'Ready';
    case 'fallback':
      return 'Fallback';
    case 'failed':
      return 'Failed';
    default:
      return 'Not built';
  }
}
